import{_ as e,o as a,c as t,ag as l}from"./chunks/framework.1N8rnUr9.js";const g=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1775715475000}'),r={name:"guide/installation.md"};function n(i,o,s,d,u,c){return a(),t("div",null,[...o[0]||(o[0]=[l('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>TubeBay can be installed like any standard WordPress plugin.</p><h2 id="method-1-wordpress-plugin-directory" tabindex="-1">Method 1: WordPress Plugin Directory <a class="header-anchor" href="#method-1-wordpress-plugin-directory" aria-label="Permalink to &quot;Method 1: WordPress Plugin Directory&quot;">​</a></h2><ol><li>In your WordPress admin, go to <strong>Plugins → Add New</strong>.</li><li>Search for <strong>&quot;TubeBay&quot;</strong>.</li><li>Click <strong>Install Now</strong>, then <strong>Activate</strong>.</li></ol><hr><h3 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h3><p>You can download the plugin in two ways:</p><ul><li>Go to <a href="https://wordpress.org/plugins/tubebay/" target="_blank" rel="noreferrer">WordPress.org plugin repository</a> and click <strong>Download</strong>. or</li><li>Get the <code>tubebay.zip</code> file from the <a href="https://github.com/wpanchorbay/tubebay/releases/latest" target="_blank" rel="noreferrer">github releases page</a>.</li></ul><h2 id="method-2-wordpress-plugin-upload" tabindex="-1">Method 2: WordPress Plugin Upload <a class="header-anchor" href="#method-2-wordpress-plugin-upload" aria-label="Permalink to &quot;Method 2: WordPress Plugin Upload&quot;">​</a></h2><ol><li><a href="#download">Download</a> the plugin.</li><li>In your WordPress admin, go to <strong>Plugins → Add New → Upload Plugin</strong>.</li><li>Choose the <code>tubebay.zip</code> file and click <strong>Install Now</strong>.</li><li>After installation completes, click <strong>Activate</strong>.</li></ol><h2 id="method-3-manual-upload-ftp" tabindex="-1">Method 3: Manual Upload (FTP) <a class="header-anchor" href="#method-3-manual-upload-ftp" aria-label="Permalink to &quot;Method 3: Manual Upload (FTP)&quot;">​</a></h2><ol><li><a href="#download">Download</a> and extract the <code>tubebay.zip</code> file.</li><li>Upload the <code>tubebay</code> folder to <code>/wp-content/plugins/</code> on your server via FTP.</li><li>In your WordPress admin, go to <strong>Plugins</strong> and activate <strong>TubeBay</strong>.</li></ol><h2 id="post-installation" tabindex="-1">Post-Installation <a class="header-anchor" href="#post-installation" aria-label="Permalink to &quot;Post-Installation&quot;">​</a></h2><p>After activation:</p><ol><li><strong>Verify WooCommerce is active</strong> — TubeBay requires WooCommerce. If WooCommerce is not active, you&#39;ll see a notice prompting you to activate it.</li><li><strong>Navigate to TubeBay</strong> — Find the <strong>TubeBay</strong> menu item in your WordPress admin sidebar.</li><li><strong>Complete Onboarding</strong> — The first time you open TubeBay, you&#39;ll see a welcome/onboarding screen where you can connect your YouTube account.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you don&#39;t see the TubeBay menu item after activation, try refreshing the admin page or clearing your browser cache.</p></div>',16)])])}const p=e(r,[["render",n]]);export{g as __pageData,p as default};
